package com.wwh.home.center.controller.device;import com.wwh.home.center.device.PcPowerEventProcessor;import com.wwh.home.center.model.common.ApiResponse;import com.wwh.home.center.model.entity.PcDevice;import com.wwh.home.center.service.PcDeviceService;import lombok.extern.slf4j.Slf4j;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.web.bind.annotation.*;import java.util.List;@Slf4j@RestController@RequestMapping("/device/pc")public class PcPowerController {    @Autowired    private PcPowerEventProcessor pcPowerEventProcessor;        @Autowired    private PcDeviceService pcDeviceService;    @GetMapping("/devices")    public ApiResponse<List<PcDevice>> getAllDevices() {        try {            List<PcDevice> devices = pcDeviceService.getAllDevices();            return ApiResponse.success("获取设备列表成功", devices);        } catch (Exception e) {            log.error("获取设备列表失败", e);            return ApiResponse.error(e.getMessage());        }    }    @PostMapping("/power/{deviceId}/{action}")    public ApiResponse<Void> handlePowerAction(            @PathVariable Long deviceId,            @PathVariable String action) {        log.info("收到电脑电源控制请求: deviceId={}, action={}", deviceId, action);                try {            switch (action.toLowerCase()) {                case "on":                    pcPowerEventProcessor.handlePowerOn(deviceId);                    return ApiResponse.success("已发送开机指令");                case "off":                    pcPowerEventProcessor.handlePowerOff(deviceId);                    return ApiResponse.success("已发送关机指令");                default:                    return ApiResponse.error("不支持的操作");            }        } catch (Exception e) {            log.error("处理电源控制请求失败", e);            return ApiResponse.error(e.getMessage());        }    }} 